// The Python script prints a JSON status line on stdout.
// Parse it so downstream nodes can branch on success/failure.
const stdout = $json["stdout"] || "";
const lastLine = stdout.trim().split("\n").pop() || "{}";
let parsed;
try {
  parsed = JSON.parse(lastLine);
} catch (e) {
  parsed = { status: "error", message: "Could not parse pipeline output" };
}
return [{ json: parsed }];

